import { Component, OnInit, ViewChild } from '@angular/core';
import { Constants } from 'src/app/constant/Constants';
import { ConstantsApp } from 'src/app/constant/ConstantsApp';
import { CommonService } from 'src/app/service/common.service';
import { UserService } from 'src/app/service/user.service';
import { LocalStorageService } from 'src/app/core/auth/local-storage.service';
import { environment } from 'src/environments/environment';
import { ApiNameConstants } from 'src/app/constant/ApiNameConstants';
import { ToastComponent } from 'src/app/layout/toast/toast.component';
import { PopupConfirmComponent } from '../form/popup-confirm/popup-confirm.component';

@Component({
  selector: 'app-organization',
  templateUrl: './organization.component.html',
  styleUrls: ['./organization.component.scss']
})
export class OrganizationComponent implements OnInit {
  @ViewChild('appToast') appToast: ToastComponent = new ToastComponent();
  @ViewChild('popupConfirmLeave') popupConfirmLeave: PopupConfirmComponent = new PopupConfirmComponent();
  user: any;
  organization: any = {};
  isOrgEditMode: boolean = false;
  messageCode: any;
  recruiterRole = ConstantsApp.RECRUITER;
  CONFIRM_LEAVE_CODE = 4;

  constructor(
    private userService: UserService,
    private commonService: CommonService,
    private localStorage: LocalStorageService
  ) {
    this.user = this.localStorage.getItem(ConstantsApp.user);
  }

  ngOnInit(): void {
    if (this.user.role === this.recruiterRole && this.user.organizationId) {
      this.fetchOrganization(this.user.organizationId);
    }
  }

  fetchOrganization(id: number) {
    const functionName = 'fetchOrganization';
    const messageLog = 'fetch organization by id';
    const apiUrl = environment.API_URI + '/bs-user/organization/' + id;
    this.commonService.getData(apiUrl, functionName, messageLog).subscribe(res => {
      if (res && res.data) {
        this.organization = res.data;
      } else {
        this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Không tìm thấy tổ chức' });
      }
    }, err => {
      console.error('Error fetching organization:', err);
      this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi tải thông tin tổ chức' });
    });
  }

  startAddOrg() {
    this.isOrgEditMode = true;
    this.organization = { name: '', des: '' };
  }

  startEditOrg() {
    this.isOrgEditMode = true;
  }

  cancelOrgEdit() {
    this.isOrgEditMode = false;
    if (this.user.organizationId) {
      this.fetchOrganization(this.user.organizationId);
    } else {
      this.organization = {};
    }
  }

  saveOrg() {
    if (!this.organization.name) {
      this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Vui lòng nhập tên tổ chức' });
      return;
    }

    if (!this.user.organizationId) {
      // Create new organization
      const functionName = 'createOrganization';
      const messageLog = 'create new organization';
      const apiUrl = environment.API_URI + '/bs-user/organization';
      const body = {
        name: this.organization.name,
        des: this.organization.des,
        userId: this.user.id
      };
      this.userService.postDatas(body, apiUrl, functionName, messageLog).subscribe(res => {
        if (res && res.data) {
          this.user.organizationId = res.data.id;
          this.organization = res.data;
          this.localStorage.setItem(ConstantsApp.user, this.user);
          this.isOrgEditMode = false;
          this.appToast.show({ messageCode: ConstantsApp.SUCCESS_CODE, message: 'Tạo tổ chức thành công' });
        } else {
          this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi tạo tổ chức' });
        }
      }, err => {
        console.error('Error creating organization:', err);
        this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi tạo tổ chức' });
      });
    } else {
      // Update existing organization
      const functionName = 'updateOrganization';
      const messageLog = 'update organization';
      const apiUrl = environment.API_URI + '/bs-user/organization/' + this.user.organizationId;
      const body = {
        name: this.organization.name,
        des: this.organization.des
      };
      this.userService.putDatas(body, apiUrl, functionName, messageLog).subscribe(res => {
        if (res && res.data) {
          this.organization = res.data;
          this.isOrgEditMode = false;
          this.appToast.show({ messageCode: ConstantsApp.SUCCESS_CODE, message: 'Cập nhật tổ chức thành công' });
        } else {
          this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi cập nhật tổ chức' });
        }
      }, err => {
        console.error('Error updating organization:', err);
        this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi cập nhật tổ chức' });
      });
    }
  }

  confirmLeaveOrg() {
    this.popupConfirmLeave.openPopup();
  }

  leaveOrg() {
    this.user.organizationId = null;
    const functionName = 'updateUser';
    const messageLog = 'update user to remove organization';
    const apiUrl = environment.API_URI + ApiNameConstants.BS_USER_UPDATE;
    this.userService.postDatas(this.user, apiUrl, functionName, messageLog).subscribe(res => {
      if (res && res.code == ConstantsApp.SUCCESS_CODE) {
        this.localStorage.setItem(ConstantsApp.user, this.user);
        this.organization = {};
        this.appToast.show({ messageCode: ConstantsApp.SUCCESS_CODE, message: 'Rời tổ chức thành công' });
      } else {
        this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi rời tổ chức' });
      }
    }, err => {
      console.error('Error updating user:', err);
      this.appToast.show({ messageCode: ConstantsApp.FAILED_CODE, message: 'Lỗi rời tổ chức' });
    });
  }
}
